-- Seed real student roster for SMT ป.4/2, school year 2569.
-- Generated from Windows-874 CSV by scripts/import-roster-csv.mjs.

on conflict (student_id) do update set
  classroom_id = excluded.classroom_id,
  seq = excluded.seq,
  student_code = excluded.student_code,
  full_name = excluded.full_name,
  display_name = excluded.display_name,
  sex = excluded.sex,
  citizen_id = excluded.citizen_id,
  birthdate_th = excluded.birthdate_th,
  registered_address = excluded.registered_address,
  current_address = excluded.current_address,
  father_name = excluded.father_name,
  father_citizen_id = excluded.father_citizen_id,
  mother_name = excluded.mother_name,
  mother_citizen_id = excluded.mother_citizen_id,
  phone = excluded.phone,
  phone_2 = excluded.phone_2,
  phone_3 = excluded.phone_3,
  guardian_name = excluded.guardian_name,
  guardian_citizen_id = excluded.guardian_citizen_id,
  guardian_relationship = excluded.guardian_relationship,
  parent_status = excluded.parent_status,
  nickname = excluded.nickname,
  health_note = excluded.health_note,
  enrolled_date = excluded.enrolled_date,
  previous_class_note = excluded.previous_class_note,
  note = excluded.note,
  needs_review = excluded.needs_review,
  active = excluded.active,
  photo_path = excluded.photo_path,
  photo_file_id = excluded.photo_file_id,
  photo_updated_at = excluded.photo_updated_at,
  photo_by = excluded.photo_by,
  updated_at = now();
